#graphql
mutation LocalizationScopedHydrationTranslationsRegister(
  $resourceId: ID!
  $translations: [TranslationInput!]!
) {
  translationsRegister(resourceId: $resourceId, translations: $translations) {
    translations {
      key
      value
      locale
      outdated
      updatedAt
      market {
        id
      }
    }
    userErrors {
      field
      message
      code
    }
  }
}

#graphql
query LocalizationScopedHydrationMixedByIds($first: Int!, $resourceIds: [ID!]!) {
  translatableResourcesByIds(first: $first, resourceIds: $resourceIds) {
    nodes {
      resourceId
      translatableContent {
        key
        value
        digest
        locale
        type
      }
      translations(locale: "af") {
        key
        value
        locale
        outdated
        updatedAt
        market {
          id
        }
      }
    }
    edges {
      cursor
      node {
        resourceId
      }
    }
    pageInfo {
      hasNextPage
      hasPreviousPage
      startCursor
      endCursor
    }
  }
}

